import React, { useEffect, useState } from 'react';
import axios from 'axios';

const CategoryManage = () => {
  const [categories, setCategories] = useState([]);
  const [nameInput, setNameInput] = useState('');
  const [editId, setEditId] = useState(null);

  // Fetch categories from backend
  const loadCategories = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/categories');
      setCategories(res.data);
    } catch (err) {
      console.error('⚠️ Could not fetch categories:', err);
    }
  };

  // Add or update a category
  const saveCategory = async () => {
    const token = localStorage.getItem('token');
    if (!token) {
      alert('You must be logged in as admin to continue.');
      return;
    }

    if (!nameInput.trim()) {
      alert('Category name cannot be empty.');
      return;
    }

    try {
      if (editId) {
        await axios.put(
          `http://localhost:5000/api/categories/${editId}`,
          { name: nameInput },
          {
            headers: { Authorization: `Bearer ${token}` },
          }
        );
        console.log('Category updated:', nameInput);
      } else {
        await axios.post(
          'http://localhost:5000/api/categories',
          { name: nameInput },
          {
            headers: { Authorization: `Bearer ${token}` },
          }
        );
        console.log('New category added:', nameInput);
      }

      setNameInput('');
      setEditId(null);
      loadCategories();
    } catch (err) {
      console.error('🚫 Error saving category:', err);
      alert('Oops! Couldn’t save category. Please try again.');
    }
  };

  // Edit existing category
  const startEdit = (category) => {
    setNameInput(category.name);
    setEditId(category.id);
  };

  // Delete a category
  const removeCategory = async (id) => {
    const token = localStorage.getItem('token');
    if (!token) {
      alert('You must be logged in as admin to continue.');
      return;
    }

    const confirm = window.confirm('Are you sure you want to delete this category?');
    if (!confirm) return;

    try {
      await axios.delete(`http://localhost:5000/api/categories/${id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      loadCategories();
    } catch (err) {
      console.error('🚫 Error deleting category:', err);
      alert('Failed to delete category. Please try again.');
    }
  };

  useEffect(() => {
    loadCategories();
  }, []);

  return (
    <div className="p-6">
      <h2 className="text-xl font-bold mb-4">Manage Categories</h2>

      <div className="mb-4 flex space-x-4">
        <input
          type="text"
          placeholder="Enter category name"
          value={nameInput}
          onChange={(e) => setNameInput(e.target.value)}
          className="border px-3 py-2 rounded w-64"
        />
        <button
          onClick={saveCategory}
          className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700"
        >
          {editId ? 'Update Category' : 'Add Category'}
        </button>
      </div>

      <table className="w-full border mt-4">
        <thead>
          <tr className="bg-gray-100">
            <th className="border px-4 py-2">ID</th>
            <th className="border px-4 py-2">Name</th>
            <th className="border px-4 py-2">Actions</th>
          </tr>
        </thead>
        <tbody>
          {categories.map((cat) => (
            <tr key={cat.id}>
              <td className="border px-4 py-2">{cat.id}</td>
              <td className="border px-4 py-2">{cat.name}</td>
              <td className="border px-4 py-2 space-x-2">
                <button
                  onClick={() => startEdit(cat)}
                  className="bg-yellow-500 text-white px-3 py-1 rounded hover:bg-yellow-600"
                >
                  Edit
                </button>
                <button
                  onClick={() => removeCategory(cat.id)}
                  className="bg-red-600 text-white px-3 py-1 rounded hover:bg-red-700"
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default CategoryManage;
